/**
  @file agent_harness.h

  AI Agent Harness & Telemetry Subsystem for L'Homme Révolté.
  Provides structured state serialization (JSON) and programmatic action
  ingestion for LLM and RL agents.

  SPDX-License-Identifier: GPL-3.0-or-later
*/

#ifndef AGENT_HARNESS_H
#define AGENT_HARNESS_H

#include <stdio.h>
#include <stdint.h>
#include <string.h>
#include "game.h"

#ifdef __cplusplus
extern "C" {
#endif

typedef struct {
  uint16_t keyBitmask;
  int16_t mouseDx;
  int16_t mouseDy;
  uint8_t stepTicks;
} SFG_AgentAction;

/**
 * Returns string name of game state enum.
 */
static inline const char* SFG_agentGetStateName(uint8_t state)
{
  switch (state)
  {
    case SFG_GAME_STATE_INIT:        return "INIT";
    case SFG_GAME_STATE_PLAYING:     return "PLAYING";
    case SFG_GAME_STATE_WIN:         return "WIN";
    case SFG_GAME_STATE_LOSE:        return "LOSE";
    case SFG_GAME_STATE_INTRO:       return "INTRO";
    case SFG_GAME_STATE_OUTRO:       return "OUTRO";
    case SFG_GAME_STATE_MAP:         return "MAP";
    case SFG_GAME_STATE_LEVEL_START: return "LEVEL_START";
    case SFG_GAME_STATE_MENU:        return "MENU";
    default:                         return "UNKNOWN";
  }
}

/**
 * Dumps complete structured state JSON to specified file stream.
 */
static inline void SFG_agentDumpStateJSON(FILE *out)
{
  if (!out) out = stdout;

  fprintf(out, "{\n");
  fprintf(out, "  \"frame\": %u,\n", (unsigned int)SFG_game.frame);
  fprintf(out, "  \"state\": \"%s\",\n", SFG_agentGetStateName(SFG_game.state));
  fprintf(out, "  \"selected_level\": %u,\n", (unsigned int)SFG_game.selectedLevel);

  // Player status
  fprintf(out, "  \"player\": {\n");
  fprintf(out, "    \"health\": %u,\n", (unsigned int)SFG_player.health);
  fprintf(out, "    \"weapon\": %u,\n", (unsigned int)SFG_player.weapon);
  fprintf(out, "    \"position\": [%d, %d, %d],\n",
          (int)SFG_player.camera.position[0],
          (int)SFG_player.camera.position[1],
          (int)SFG_player.camera.position[2]);
  fprintf(out, "    \"direction\": [%d, %d],\n",
          (int)SFG_player.direction.x,
          (int)SFG_player.direction.y);
  fprintf(out, "    \"square_coords\": [%d, %d],\n",
          (int)SFG_player.squarePosition[0],
          (int)SFG_player.squarePosition[1]);
  fprintf(out, "    \"cards_bitmask\": %u,\n", (unsigned int)(SFG_player.cards & 0x07));
  fprintf(out, "    \"ammo\": [%u, %u, %u]\n",
          (unsigned int)SFG_player.ammo[0],
          (unsigned int)SFG_player.ammo[1],
          (unsigned int)SFG_player.ammo[2]);
  fprintf(out, "  },\n");

  // Active monsters count & array
  uint16_t activeMonsters = 0;
  for (uint8_t i = 0; i < SFG_MAX_MONSTERS; ++i)
  {
    if (SFG_currentLevel.monsters[i].health > 0 &&
        SFG_MR_STATE(SFG_currentLevel.monsters[i]) != SFG_MONSTER_STATE_INACTIVE &&
        SFG_MR_STATE(SFG_currentLevel.monsters[i]) != SFG_MONSTER_STATE_DEAD)
    {
      activeMonsters++;
    }
  }

  fprintf(out, "  \"monsters\": {\n");
  fprintf(out, "    \"active_count\": %u,\n", activeMonsters);
  fprintf(out, "    \"entities\": [\n");

  uint16_t printedMonsters = 0;
  for (uint8_t i = 0; i < SFG_MAX_MONSTERS; ++i)
  {
    if (SFG_currentLevel.monsters[i].health > 0 &&
        SFG_MR_STATE(SFG_currentLevel.monsters[i]) != SFG_MONSTER_STATE_INACTIVE &&
        SFG_MR_STATE(SFG_currentLevel.monsters[i]) != SFG_MONSTER_STATE_DEAD)
    {
      if (printedMonsters > 0) fprintf(out, ",\n");
      fprintf(out, "      {\"id\": %u, \"type\": %u, \"health\": %u, \"coords\": [%u, %u], \"state\": %u}",
              i,
              SFG_MR_TYPE(SFG_currentLevel.monsters[i]),
              SFG_currentLevel.monsters[i].health,
              SFG_currentLevel.monsters[i].coords[0],
              SFG_currentLevel.monsters[i].coords[1],
              SFG_MR_STATE(SFG_currentLevel.monsters[i]));
      printedMonsters++;
    }
  }
  fprintf(out, "\n    ]\n");
  fprintf(out, "  }\n");
  fprintf(out, "}\n");
  fflush(out);
}

/**
 * Parses action input string into SFG_AgentAction struct.
 * Expected input format: "KEYS_MASK MOUSE_DX MOUSE_DY TICKS" or JSON
 */
static inline SFG_AgentAction SFG_agentParseActionLine(const char *line)
{
  SFG_AgentAction action;
  action.keyBitmask = 0;
  action.mouseDx = 0;
  action.mouseDy = 0;
  action.stepTicks = 1;

  if (!line || strlen(line) == 0) return action;

  // Simple token parsing: <key_bitmask_hex> <mouse_dx> <mouse_dy> <ticks>
  unsigned int kMask = 0;
  int dx = 0, dy = 0, ticks = 1;
  if (sscanf(line, "%x %d %d %d", &kMask, &dx, &dy, &ticks) >= 1)
  {
    action.keyBitmask = (uint16_t)kMask;
    action.mouseDx = (int16_t)dx;
    action.mouseDy = (int16_t)dy;
    action.stepTicks = (ticks > 0) ? (uint8_t)ticks : 1;
  }
  return action;
}

#ifdef __cplusplus
}
#endif

#endif // AGENT_HARNESS_H

/**
  @file agent_test.c

  Headless AI Agent Harness Execution Frontend for L'Homme Révolté.
  Exposes tick-by-tick I/O loop: reads actions, advances game logic,
  and outputs JSON telemetry.

  SPDX-License-Identifier: GPL-3.0-or-later
*/

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define SFG_SCREEN_RESOLUTION_X 64
#define SFG_SCREEN_RESOLUTION_Y 32
#define SFG_BACKGROUND_BLUR 0
#define SFG_DITHERED_SHADOW 0
#define SFG_FPS 30

#include "game.h"
#include "sounds.h"
#include "agent_harness.h"

static uint8_t screen[SFG_SCREEN_RESOLUTION_X * SFG_SCREEN_RESOLUTION_Y];
static uint16_t currentKeyBitmask = 0;
static int16_t currentMouseDx = 0;
static int16_t currentMouseDy = 0;
static uint32_t simulatedTimeMs = 0;

int8_t SFG_keyPressed(uint8_t key)
{
  if (key >= SFG_KEY_COUNT) return 0;
  return (currentKeyBitmask >> key) & 0x01;
}

void SFG_getMouseOffset(int16_t *x, int16_t *y)
{
  *x = currentMouseDx;
  *y = currentMouseDy;
  currentMouseDx = 0;
  currentMouseDy = 0;
}

uint32_t SFG_getTimeMs(void)
{
  return simulatedTimeMs;
}

void SFG_sleepMs(uint16_t timeMs)
{
  simulatedTimeMs += timeMs;
}

static inline void SFG_setPixel(uint16_t x, uint16_t y, uint8_t colorIndex)
{
  if (x < SFG_SCREEN_RESOLUTION_X && y < SFG_SCREEN_RESOLUTION_Y)
    screen[y * SFG_SCREEN_RESOLUTION_X + x] = colorIndex;
}

void SFG_playSound(uint8_t soundIndex, uint8_t volume) {}
void SFG_setMusic(uint8_t value) {}
void SFG_processEvent(uint8_t event, uint8_t data) {}
void SFG_save(uint8_t data[SFG_SAVE_SIZE]) {}
uint8_t SFG_load(uint8_t data[SFG_SAVE_SIZE]) { return 0; }

int main(int argc, char *argv[])
{
  int targetLevel = 0;
  int numTicks = 5;
  uint8_t interactiveMode = 0;

  for (int i = 1; i < argc; ++i)
  {
    if (strcmp(argv[i], "--level") == 0 && i + 1 < argc)
    {
      targetLevel = atoi(argv[i + 1]);
      i++;
    }
    else if (strcmp(argv[i], "--ticks") == 0 && i + 1 < argc)
    {
      numTicks = atoi(argv[i + 1]);
      i++;
    }
    else if (strcmp(argv[i], "--interactive") == 0)
    {
      interactiveMode = 1;
    }
  }

  SFG_init();

  if (targetLevel >= 0 && targetLevel < SFG_NUMBER_OF_LEVELS)
  {
    SFG_game.selectedLevel = targetLevel;
    SFG_setAndInitLevel(targetLevel);
    SFG_game.state = SFG_GAME_STATE_PLAYING;
  }

  if (interactiveMode)
  {
    fprintf(stderr, "=== L'Homme Révolté AI Harness (Interactive Mode) ===\n");
    fprintf(stderr, "Format: <key_bitmask_hex> <mouse_dx> <mouse_dy> <step_ticks>\n");
    fprintf(stderr, "Example: '0001 0 0 1' (Press UP for 1 frame)\n\n");

    char buffer[256];
    SFG_agentDumpStateJSON(stdout);

    while (fgets(buffer, sizeof(buffer), stdin))
    {
      SFG_AgentAction act = SFG_agentParseActionLine(buffer);
      currentKeyBitmask = act.keyBitmask;
      currentMouseDx = act.mouseDx;
      currentMouseDy = act.mouseDy;

      for (uint8_t t = 0; t < act.stepTicks; ++t)
      {
        simulatedTimeMs += (1000 / SFG_FPS);
        if (!SFG_mainLoopBody()) break;
      }

      SFG_agentDumpStateJSON(stdout);
    }
  }
  else
  {
    // Batch execution mode: run specified ticks and output initial & final JSON state
    fprintf(stderr, "[Agent Harness] Running level %d for %d ticks...\n", targetLevel, numTicks);

    // Initial State Dump
    SFG_agentDumpStateJSON(stdout);

    // Simulate straight walk forward (SFG_KEY_UP is key index 0 -> bitmask 0x0001)
    currentKeyBitmask = 0x0001; 

    for (int t = 0; t < numTicks; ++t)
    {
      simulatedTimeMs += (1000 / SFG_FPS);
      if (!SFG_mainLoopBody()) break;
    }

    // Final State Dump
    SFG_agentDumpStateJSON(stdout);
  }

  return 0;
}

