import json
import sys
import subprocess
import time

def main():
    print("Starting smart bot...")
    cmd = ["../build/revolte_sdl", "--agent-sync", "--lhrwarp", "0"]
    proc = subprocess.Popen(cmd, stdin=subprocess.PIPE, stdout=subprocess.PIPE, text=True, bufsize=1)

    with open("full_game_run.txt", "w") as f:
        while True:
            line = proc.stdout.readline()
            if not line:
                break

            line = line.strip()
            if not line.startswith("{"):
                print(line)
                if "WIN" in line or "OUTRO" in line or "AI WON" in line:
                    print("VICTORY DETECTED!")
                    break
                continue

            try:
                state = json.loads(line)
            except:
                continue

            # Parse state
            screen = state.get("screen_ascii", [])
            game_state = state.get("game_state", 0)

            if game_state == 5: # WIN
                print("Game Won!")
                break
            elif game_state == 4: # LOSE
                print("Game Over!")
                break

            # Right-hand rule logic
            enemy_in_sight = False
            for r in range(12, 20):
                if len(screen) > r and len(screen[r]) > 38:
                    for c in range(26, 38):
                        if screen[r][c] not in (' ', '@', '.', '_', '#'):
                            enemy_in_sight = True

            ahead_wall = False
            for r in range(12, 20):
                if len(screen) > r and len(screen[r]) > 34:
                    if '@' in screen[r][30:34]:
                        ahead_wall = True

            right_wall = False
            for r in range(12, 20):
                if len(screen) > r and len(screen[r]) > 48:
                    if '@' in screen[r][44:48]:
                        right_wall = True

            # Decisions
            action = "0000 0 0 10" # Default wait

            if enemy_in_sight:
                action = "0010 0 0 10" # Shoot
            elif ahead_wall:
                action = "0008 0 0 20" # Turn left
            elif not right_wall:
                # Turn right and move forward
                action = "0002 0 0 20" # Turn right
            else:
                action = "0001 0 0 20" # Move forward

            # Write action
            proc.stdin.write(action + "\n")
            proc.stdin.flush()
            f.write(action + "\n")
            f.flush()

    print("Run finished!")

if __name__ == "__main__":
    main()

