static char * test_frame_calc() {
    SFG_MapImage static_img = { .frames = 1, .fps = 10 };
    SFG_MapImage anim_img = { .frames = 4, .fps = 10 }; // 10 frames per second means each frame is 100ms

    // Static image should always return 0
    mu_assert("static img failed", SFG_getMapImageFrame(&static_img, 500) == 0);

    // Animated image tests
    // 0ms = frame 0
    mu_assert("anim 0ms", SFG_getMapImageFrame(&anim_img, 0) == 0);
    // 50ms = 0.5 frames = frame 0
    mu_assert("anim 50ms", SFG_getMapImageFrame(&anim_img, 50) == 0);
    // 100ms = 1 frame = frame 1
    mu_assert("anim 100ms", SFG_getMapImageFrame(&anim_img, 100) == 1);
    // 250ms = 2.5 frames = frame 2
    mu_assert("anim 250ms", SFG_getMapImageFrame(&anim_img, 250) == 2);
    // 400ms = 4 frames = frame 0 (wrap around modulo 4)
    mu_assert("anim 400ms wrap", SFG_getMapImageFrame(&anim_img, 400) == 0);

    return 0;
}

static char * all_tests() {
    mu_run_test(test_metadata_struct);
    mu_run_test(test_frame_calc);
    return 0;
}

