/**
  @file mapset.h

  Mapset definition, platform capability checking, and dynamic loading gate.

  A Mapset is a self-contained bundle of levels, resources, and metadata that
  declares its hardware/platform requirements. The engine MUST refuse to load
  a mapset if the target platform does not satisfy every declared requirement.

  SPDX-License-Identifier: GPL-3.0-or-later
*/

#ifndef _LHR_MAPSET_H
#define _LHR_MAPSET_H

#include <stdint.h>

/* ======================== PLATFORM CAPABILITY FLAGS ======================== */

/** Bitmask flags describing what a platform can provide. */
#define LHR_CAP_KEYS_4        (1u << 0)  /**< Platform has >= 4 action keys. */
#define LHR_CAP_KEYS_7        (1u << 1)  /**< Platform has >= 7 keys (A/B/C + dpad). */
#define LHR_CAP_KEYS_16       (1u << 2)  /**< Platform has full 16-key layout. */
#define LHR_CAP_MOUSE          (1u << 3)  /**< Platform has a pointing device. */
#define LHR_CAP_DUAL_SCREEN    (1u << 4)  /**< Platform renders to two displays. */
#define LHR_CAP_AUDIO_PCM      (1u << 5)  /**< Platform can stream PCM WAV. */
#define LHR_CAP_AUDIO_MIDI     (1u << 6)  /**< Platform has embedded MIDI synth. */
#define LHR_CAP_AUDIO_BYTEBEAT (1u << 7)  /**< Platform has procedural bytebeat. */
#define LHR_CAP_FILESYSTEM     (1u << 8)  /**< Platform can fopen/fread files. */
#define LHR_CAP_HIGH_RES       (1u << 9)  /**< Platform supports >= 640x480. */
#define LHR_CAP_COLOR_DEPTH_16 (1u << 10) /**< Platform has >= 16-bit color. */
#define LHR_CAP_SAVE_FILE      (1u << 11) /**< Platform can persist save data. */

/* ======================== MAPSET METADATA ================================= */

/**
  Magic bytes identifying a mapset file on disk.
  ASCII: "LHRM" (L'Homme Révolté Mapset).
*/
#define LHR_MAPSET_MAGIC 0x4D52484Cu

/**
  Current mapset format version. Increment when the binary layout changes.
*/
#define LHR_MAPSET_VERSION 1u

/**
  Maximum length for mapset identifiers (name, author) including NUL.
*/
#define LHR_MAPSET_NAME_MAX 64

/**
  Metadata header for a Mapset. This struct is used both at compile-time
  (baked-in mapsets) and at runtime (dynamic loading from file).
*/
typedef struct
{
  char name[LHR_MAPSET_NAME_MAX];       /**< Human-readable mapset name. */
  char author[LHR_MAPSET_NAME_MAX];     /**< Author / team. */
  uint32_t version;                      /**< Mapset content version. */
  uint32_t levelCount;                   /**< Number of levels in the mapset. */
  uint32_t requiredCapabilities;         /**< Bitmask of LHR_CAP_* flags the
                                              mapset REQUIRES to function. */
  uint32_t optionalCapabilities;         /**< Bitmask of LHR_CAP_* flags the
                                              mapset CAN USE but doesn't need. */
} LHR_MapsetMeta;

/* ======================== PLATFORM DECLARATION ============================ */

/**
  Each frontend must define this before including game.h (or this file) to
  declare what the compilation target can actually do.
  Example for PC/SDL:
    #define LHR_PLATFORM_CAPABILITIES ( \
      LHR_CAP_KEYS_16 | LHR_CAP_MOUSE | LHR_CAP_AUDIO_PCM | \
      LHR_CAP_AUDIO_MIDI | LHR_CAP_AUDIO_BYTEBEAT | \
      LHR_CAP_FILESYSTEM | LHR_CAP_HIGH_RES | LHR_CAP_SAVE_FILE )
*/
#ifndef LHR_PLATFORM_CAPABILITIES
  #define LHR_PLATFORM_CAPABILITIES 0u
#endif

/* ======================== CAPABILITY CHECKING ============================= */

/**
  Returns 1 if the platform satisfies ALL required capabilities of a mapset,
  0 otherwise. This is the gatekeeper: the engine MUST call this before loading.
*/
static inline int LHR_mapsetCompatible(const LHR_MapsetMeta *meta)
{
  return (meta->requiredCapabilities & LHR_PLATFORM_CAPABILITIES)
         == meta->requiredCapabilities;
}

/**
  Populates a human-readable error string listing the first missing capability.
  Returns the missing bitmask, or 0 if compatible.
*/
static inline uint32_t LHR_mapsetMissingCaps(const LHR_MapsetMeta *meta)
{
  return meta->requiredCapabilities & ~LHR_PLATFORM_CAPABILITIES;
}

/* ======================== CAPABILITY NAME TABLE ============================ */

/**
  Lookup table mapping each capability bit to a human-readable name.
  Useful for error messages ("mapset requires MOUSE but platform lacks it").
*/
static const char *LHR_capabilityNames[] = {
  "4-key input",         /* bit 0  */
  "7-key input",         /* bit 1  */
  "16-key input",        /* bit 2  */
  "mouse/pointer",       /* bit 3  */
  "dual screen",         /* bit 4  */
  "PCM WAV audio",       /* bit 5  */
  "MIDI audio",          /* bit 6  */
  "bytebeat audio",      /* bit 7  */
  "filesystem access",   /* bit 8  */
  "high resolution",     /* bit 9  */
  "16-bit color",        /* bit 10 */
  "save file support"    /* bit 11 */
};

#define LHR_CAPABILITY_COUNT 12

/**
  Log all missing capabilities to the engine log.
  Uses the LHR_LOG macro defined by the frontend.
*/
static inline void LHR_logMissingCapabilities(const LHR_MapsetMeta *meta)
{
  uint32_t missing = LHR_mapsetMissingCaps(meta);
  if (missing == 0) return;

  LHR_LOG("Mapset compatibility failure:");

  for (int i = 0; i < LHR_CAPABILITY_COUNT; ++i)
  {
    if (missing & (1u << i))
    {
      LHR_LOG("  MISSING: ");
      LHR_LOG(LHR_capabilityNames[i]);
    }
  }
}

/* ======================== DYNAMIC LOADING GATE ============================ */

/**
  Compile-time switch. When set to 1, the engine can load .lhrm mapset files
  from disk at runtime. When 0, only baked-in mapsets are available.
*/
#ifndef LHR_DYNAMIC_MAPSETS
  #define LHR_DYNAMIC_MAPSETS 0
#endif

#if LHR_DYNAMIC_MAPSETS

/**
  On-disk file header for a .lhrm mapset file.
  Layout:
    [4 bytes] magic   = LHR_MAPSET_MAGIC
    [4 bytes] version = LHR_MAPSET_VERSION
    [sizeof(LHR_MapsetMeta)] metadata
    [... level data, resources, etc. ...]
*/
typedef struct
{
  uint32_t magic;
  uint32_t formatVersion;
  LHR_MapsetMeta meta;
} LHR_MapsetFileHeader;

#include <stdio.h>

/**
  Attempt to load a mapset file header from disk. Returns 1 on success, 0 on
  failure (bad magic, wrong version, or file I/O error). Does NOT load the
  level data itself — that happens in a separate pass after capability checking.
*/
static inline int LHR_loadMapsetHeader(const char *path,
                                        LHR_MapsetFileHeader *out)
{
  FILE *f = fopen(path, "rb");
  if (!f) return 0;

  if (fread(out, sizeof(LHR_MapsetFileHeader), 1, f) != 1)
  {
    fclose(f);
    return 0;
  }

  fclose(f);

  if (out->magic != LHR_MAPSET_MAGIC)
  {
    LHR_LOG("Mapset file: bad magic number.");
    return 0;
  }

  if (out->formatVersion != LHR_MAPSET_VERSION)
  {
    LHR_LOG("Mapset file: unsupported format version.");
    return 0;
  }

  return 1;
}

/**
  Full dynamic load gate: reads the header, checks compatibility, and rejects
  if the platform doesn't meet requirements. Returns 1 if the mapset is safe
  to proceed loading, 0 otherwise.
*/
static inline int LHR_tryLoadMapset(const char *path,
                                     LHR_MapsetFileHeader *out)
{
  if (!LHR_loadMapsetHeader(path, out))
    return 0;

  if (!LHR_mapsetCompatible(&out->meta))
  {
    LHR_logMissingCapabilities(&out->meta);
    return 0;
  }

  return 1;
}

#endif /* LHR_DYNAMIC_MAPSETS */

#endif /* _LHR_MAPSET_H */

/**
  @file test_mapset.c

  Unit tests for core/mapset.h capability checking logic.

  Compile:
    cc -std=c99 -Icore -o tests/test_mapset tests/test_mapset.c && ./tests/test_mapset

  SPDX-License-Identifier: GPL-3.0-or-later
*/

#include <stdio.h>
#include <string.h>
#include <assert.h>

/* Simulate a PC platform with most capabilities */
#define LHR_PLATFORM_CAPABILITIES ( \
  LHR_CAP_KEYS_16 | LHR_CAP_MOUSE | LHR_CAP_AUDIO_PCM | \
  LHR_CAP_AUDIO_BYTEBEAT | LHR_CAP_FILESYSTEM | LHR_CAP_SAVE_FILE )

#define LHR_LOG(s) fprintf(stderr, "%s\n", s)

#include "mapset.h"

static int tests_run = 0;
static int tests_passed = 0;

#define TEST(name) do { \
  tests_run++; \
  printf("  TEST: %-50s ", #name); \
} while(0)

#define PASS() do { tests_passed++; printf("[PASS]\n"); } while(0)
#define FAIL(msg) do { printf("[FAIL] %s\n", msg); } while(0)

/* ---------- helpers ---------- */

static LHR_MapsetMeta make_meta(const char *name, uint32_t required)
{
  LHR_MapsetMeta m;
  memset(&m, 0, sizeof(m));
  strncpy(m.name, name, LHR_MAPSET_NAME_MAX - 1);
  m.requiredCapabilities = required;
  m.levelCount = 1;
  m.version = 1;
  return m;
}

/* ---------- tests ---------- */

void test_compatible_mapset_accepted(void)
{
  TEST(compatible_mapset_accepted);
  LHR_MapsetMeta m = make_meta("basic", LHR_CAP_KEYS_16 | LHR_CAP_FILESYSTEM);
  if (LHR_mapsetCompatible(&m) == 1 && LHR_mapsetMissingCaps(&m) == 0)
    PASS();
  else
    FAIL("should be compatible");
}

void test_incompatible_mapset_rejected(void)
{
  TEST(incompatible_mapset_rejected);
  /* Require dual screen — our simulated platform doesn't have it */
  LHR_MapsetMeta m = make_meta("dual_screen_mod",
    LHR_CAP_KEYS_16 | LHR_CAP_DUAL_SCREEN);
  if (LHR_mapsetCompatible(&m) == 0)
    PASS();
  else
    FAIL("should be incompatible (dual screen missing)");
}

void test_missing_caps_reports_correct_bits(void)
{
  TEST(missing_caps_reports_correct_bits);
  LHR_MapsetMeta m = make_meta("midi_mod",
    LHR_CAP_AUDIO_MIDI | LHR_CAP_DUAL_SCREEN | LHR_CAP_KEYS_16);
  uint32_t missing = LHR_mapsetMissingCaps(&m);
  /* We defined platform WITHOUT MIDI and WITHOUT DUAL_SCREEN */
  if ((missing & LHR_CAP_AUDIO_MIDI) && (missing & LHR_CAP_DUAL_SCREEN)
      && !(missing & LHR_CAP_KEYS_16))
    PASS();
  else
    FAIL("wrong missing bits");
}

void test_no_requirements_always_compatible(void)
{
  TEST(no_requirements_always_compatible);
  LHR_MapsetMeta m = make_meta("empty", 0);
  if (LHR_mapsetCompatible(&m) == 1)
    PASS();
  else
    FAIL("zero requirements should always pass");
}

void test_optional_caps_dont_block(void)
{
  TEST(optional_caps_dont_block);
  LHR_MapsetMeta m = make_meta("optional_midi", LHR_CAP_KEYS_16);
  m.optionalCapabilities = LHR_CAP_AUDIO_MIDI; /* optional, not required */
  if (LHR_mapsetCompatible(&m) == 1)
    PASS();
  else
    FAIL("optional caps should not block loading");
}

void test_all_platform_caps_satisfied(void)
{
  TEST(all_platform_caps_satisfied);
  /* Require exactly what the platform has */
  LHR_MapsetMeta m = make_meta("full_pc",
    LHR_CAP_KEYS_16 | LHR_CAP_MOUSE | LHR_CAP_AUDIO_PCM |
    LHR_CAP_AUDIO_BYTEBEAT | LHR_CAP_FILESYSTEM | LHR_CAP_SAVE_FILE);
  if (LHR_mapsetCompatible(&m) == 1 && LHR_mapsetMissingCaps(&m) == 0)
    PASS();
  else
    FAIL("all caps present, should pass");
}

#if LHR_DYNAMIC_MAPSETS
void test_load_bad_magic_rejected(void)
{
  TEST(load_bad_magic_rejected);
  const char *path = "/tmp/lhr_test_bad.lhrm";
  FILE *f = fopen(path, "wb");
  uint32_t bad_magic = 0xDEADBEEF;
  uint32_t ver = LHR_MAPSET_VERSION;
  LHR_MapsetMeta m = make_meta("bad", 0);
  fwrite(&bad_magic, 4, 1, f);
  fwrite(&ver, 4, 1, f);
  fwrite(&m, sizeof(m), 1, f);
  fclose(f);

  LHR_MapsetFileHeader hdr;
  if (LHR_loadMapsetHeader(path, &hdr) == 0)
    PASS();
  else
    FAIL("bad magic should be rejected");
}

void test_load_valid_header_accepted(void)
{
  TEST(load_valid_header_accepted);
  const char *path = "/tmp/lhr_test_good.lhrm";
  FILE *f = fopen(path, "wb");
  uint32_t magic = LHR_MAPSET_MAGIC;
  uint32_t ver = LHR_MAPSET_VERSION;
  LHR_MapsetMeta m = make_meta("good", LHR_CAP_KEYS_16);
  fwrite(&magic, 4, 1, f);
  fwrite(&ver, 4, 1, f);
  fwrite(&m, sizeof(m), 1, f);
  fclose(f);

  LHR_MapsetFileHeader hdr;
  if (LHR_loadMapsetHeader(path, &hdr) == 1
      && hdr.magic == LHR_MAPSET_MAGIC
      && strcmp(hdr.meta.name, "good") == 0)
    PASS();
  else
    FAIL("valid header should be accepted");
}

void test_tryload_rejects_incompatible(void)
{
  TEST(tryload_rejects_incompatible);
  const char *path = "/tmp/lhr_test_incompat.lhrm";
  FILE *f = fopen(path, "wb");
  uint32_t magic = LHR_MAPSET_MAGIC;
  uint32_t ver = LHR_MAPSET_VERSION;
  LHR_MapsetMeta m = make_meta("needs_dual", LHR_CAP_DUAL_SCREEN);
  fwrite(&magic, 4, 1, f);
  fwrite(&ver, 4, 1, f);
  fwrite(&m, sizeof(m), 1, f);
  fclose(f);

  LHR_MapsetFileHeader hdr;
  if (LHR_tryLoadMapset(path, &hdr) == 0)
    PASS();
  else
    FAIL("incompatible mapset should be rejected by tryload");
}
#endif /* LHR_DYNAMIC_MAPSETS */

int main(void)
{
  printf("=== Mapset Capability Tests ===\n");

  test_compatible_mapset_accepted();
  test_incompatible_mapset_rejected();
  test_missing_caps_reports_correct_bits();
  test_no_requirements_always_compatible();
  test_optional_caps_dont_block();
  test_all_platform_caps_satisfied();

#if LHR_DYNAMIC_MAPSETS
  printf("\n=== Dynamic Loading Tests ===\n");
  test_load_bad_magic_rejected();
  test_load_valid_header_accepted();
  test_tryload_rejects_incompatible();
#else
  printf("\n(Dynamic loading tests skipped: LHR_DYNAMIC_MAPSETS=0)\n");
#endif

  printf("\n%d/%d tests passed.\n", tests_passed, tests_run);
  return (tests_passed == tests_run) ? 0 : 1;
}

import pytest
from pytest_bdd import scenarios, given, when, then, parsers

# Load the scenarios from the feature file
scenarios('../features/mapsets.feature')

@pytest.fixture
def engine_state():
    return {
        'platform_capabilities': {},
        'mapset_requirements': {},
        'mapset_optional': {},
        'dynamic_mapsets_enabled': False,
        'load_attempted': False,
        'load_success': False,
        'errors': []
    }

# --- Given steps ---

@given(parsers.parse('a target compilation platform with {keys:d} keys'))
def platform_capabilities(engine_state, keys):
    engine_state['platform_capabilities']['keys'] = keys

@given(parsers.parse('a mapset metadata defining a requirement of {keys:d} keys'))
def mapset_requirements_keys(engine_state, keys):
    engine_state['mapset_requirements']['keys'] = keys

@given('a mapset with no hardware requirements')
def mapset_no_requirements(engine_state):
    engine_state['mapset_requirements'] = {}

@given('a mapset that optionally uses MIDI audio')
def mapset_optional_midi(engine_state):
    engine_state['mapset_requirements'] = {}
    engine_state['mapset_optional']['midi'] = True

@given('a mapset metadata defining a requirement of dual screen')
def mapset_requires_dual_screen(engine_state):
    engine_state['mapset_requirements']['dual_screen'] = True

@given(parsers.parse('the engine is compiled with LHR_DYNAMIC_MAPSETS={value:d}'))
def dynamic_mapsets(engine_state, value):
    engine_state['dynamic_mapsets_enabled'] = bool(value)

@given(parsers.parse('a valid mapset file "{filename}" is present'))
def mapset_file(engine_state, filename):
    engine_state['target_file'] = filename

# --- When steps ---

@when('the engine attempts to load the mapset')
def attempt_load(engine_state):
    engine_state['load_attempted'] = True
    caps = engine_state['platform_capabilities']
    reqs = engine_state['mapset_requirements']

    # Check keys requirement
    if reqs.get('keys') and int(reqs['keys']) > int(caps.get('keys', 0)):
        engine_state['errors'].append("insufficient keys")
        engine_state['load_success'] = False
        return

    # Check dual screen requirement
    if reqs.get('dual_screen') and not caps.get('dual_screen', False):
        engine_state['errors'].append("missing dual screen")
        engine_state['load_success'] = False
        return

    engine_state['load_success'] = True

@when(parsers.parse('the user requests to load "{filename}"'))
def load_dynamic(engine_state, filename):
    if not engine_state['dynamic_mapsets_enabled']:
        engine_state['errors'].append("dynamic loading is disabled")
        engine_state['load_success'] = False
    else:
        engine_state['load_success'] = True

# --- Then steps ---

@then('the engine should refuse to load the mapset')
def verify_refusal(engine_state):
    assert engine_state['load_success'] is False

@then('the engine should accept the mapset')
def verify_acceptance(engine_state):
    assert engine_state['load_success'] is True

@then(parsers.parse('log an error indicating {error_msg}'))
def verify_error(engine_state, error_msg):
    assert any(error_msg in err for err in engine_state['errors'])

@then('the engine should parse the file header')
def parse_header(engine_state):
    assert engine_state['dynamic_mapsets_enabled'] is True

@then('successfully load the mapset if platform requirements are met')
def load_success(engine_state):
    assert engine_state['load_success'] is True

